const body = $json.body && typeof $json.body === 'object' ? $json.body : $json;
const expectedSecret = ($vars && ($vars.IDENTITY_VERIFICATION_WEBHOOK_TOKEN || $vars.DOCUMENT_VALIDATION_SERVICE_SECRET)) || '';
if (expectedSecret) {
  const headers = $json.headers || {};
  const providedSecret = headers['x-instawork-identity-secret'] || headers['X-Instawork-Identity-Secret'] || headers['authorization']?.replace(/^Bearer\s+/i, '') || '';
  if (providedSecret !== expectedSecret) {
    console.log('[AUTH] REJECTED: missing or invalid webhook secret');
    return [{ json: { valid: false, responseCode: 401, response: { success: false, requestId: body.requestId || null, error: { code: 'UNAUTHORIZED', message: 'Unauthorized request.' }, analysis: null } } }];
  }
}
const allowedTypes = ['drivers-license','state-id','passport','passport-card','permanent-resident-card','employment-authorization-card','military-id','unknown'];
const allowedSides = ['front','back'];
const p = body.profile || {};
const imgLen = (body.imageBase64 || '').length;

console.log('[INTAKE] requestId=' + (body.requestId || 'MISSING'));
console.log('[INTAKE] documentType=' + (body.selectedDocumentType || 'MISSING') + ' side=' + (body.documentSide || 'MISSING'));
console.log('[INTAKE] profile: firstName=' + (p.legalFirstName || 'MISSING') + ' lastName=' + (p.legalLastName || 'MISSING') + ' DOB=' + (p.dateOfBirth || 'MISSING'));
console.log('[INTAKE] imageBase64 length=' + imgLen + ' chars (~' + Math.round(imgLen * 0.75 / 1024) + ' KB)');

const missing = [];
for (const path of ['requestId','selectedDocumentType','documentSide','imageBase64','profile.legalFirstName','profile.legalLastName','profile.dateOfBirth']) {
  const value = path.split('.').reduce((acc, key) => acc && acc[key], body);
  if (value === undefined || value === null || value === '') missing.push(path);
}
const invalid = [];
if (body.selectedDocumentType && !allowedTypes.includes(body.selectedDocumentType)) invalid.push('selectedDocumentType');
if (body.documentSide && !allowedSides.includes(body.documentSide)) invalid.push('documentSide');

if (missing.length || invalid.length) {
  console.log('[INTAKE] REJECTED: missing=' + JSON.stringify(missing) + ' invalid=' + JSON.stringify(invalid));
  return [{ json: { valid: false, response: { success: false, requestId: body.requestId || null, error: { code: 'INVALID_REQUEST', message: 'Missing or invalid fields.', missing, invalid }, analysis: null } } }];
}
console.log('[INTAKE] VALID - proceeding to image conversion');
return [{ json: { ...body, valid: true } }];

let original = {};
try { original = ($('Convert Base64 To Binary')?.item?.json) || {}; } catch (e) { console.log('[S3-FAIL] could not read original: ' + e.message); }
const error = $json || {};
const message = error.message || error.error?.message || error.error || 'S3 upload failed';
console.log('[S3-UPLOAD-FAIL] Native AWS S3 node failed: ' + JSON.stringify(error).slice(0, 1000));
return [{
  json: {
    success: false,
    requestId: original.requestId || null,
    source: 'n8n-native-s3-upload',
    s3FileKey: original.s3Key || null,
    s3FileUrl: original.s3FileUrl || null,
    error: {
      code: error.code || 'S3_UPLOAD_FAILED',
      message,
      rawResponse: JSON.stringify(error).slice(0, 2000)
    },
    analysis: null
  }
}];

// Decode the base64 image and compute SigV4 headers locally.
// This avoids n8n's AWS credential helper, which calls s3:GetBucketLocation.
const crypto = require('crypto');

const accessKey = ($vars && $vars.IV_AWS_ACCESS_KEY_ID) || '';
const secretKey = ($vars && $vars.IV_AWS_SECRET_ACCESS_KEY) || '';
const region = ($vars && $vars.IV_AWS_REGION) || 'us-west-2';
const bucket = ($vars && $vars.IV_AWS_BUCKET) || 'instawork-prod-ops-w2-i9-docs-dev';
const service = 's3';

if (!accessKey || !secretKey) {
  throw new Error('Missing n8n Variables IV_AWS_ACCESS_KEY_ID and/or IV_AWS_SECRET_ACCESS_KEY.');
}

const input = $json;
const raw = String(input.imageBase64 || '');
const match = raw.match(/^data:(.*?);base64,(.*)$/);
const mimeType = match ? (match[1] || 'image/png') : 'image/png';
const base64 = match ? match[2] : raw;
const extByMime = { 'image/jpeg': 'jpg', 'image/jpg': 'jpg', 'image/png': 'png', 'image/webp': 'webp' };
const extension = extByMime[mimeType] || 'png';

const safePart = (value) => String(value || 'unknown').trim().replace(/[^A-Za-z0-9._-]+/g, '-').replace(/^-+|-+$/g, '') || 'unknown';
const safeRequestId = safePart(input.requestId);
const safeDocType = safePart(input.selectedDocumentType);
const safeSide = safePart(input.documentSide);
const fileName = `${safeRequestId}-${safeDocType}-${safeSide}.${extension}`;

const p = input.profile || {};
const safeUserId = safePart(
  input.userId || input.workerId || input.accountId ||
  p.userId || p.workerId || p.accountId || safeRequestId
);
const flowHint = String(input.flow || input.documentFlow || input.documentCategory || '').toLowerCase();
const s3Prefix = flowHint.includes('i9') ? 'i9' : 'w2';
const s3Key = `${s3Prefix}/${safeUserId}/${fileName}`;

const buffer = Buffer.from(base64, 'base64');
if (!buffer.length) throw new Error('imageBase64 decoded to an empty file');

const host = `${bucket}.s3.${region}.amazonaws.com`;
const method = 'PUT';
const now = new Date();
const amzDate = now.toISOString().replace(/[:-]|\.\d{3}/g, '');
const dateStamp = amzDate.substring(0, 8);
const payloadHash = crypto.createHash('sha256').update(buffer).digest('hex');
const canonicalUri = '/' + s3Key.split('/').map((segment) => encodeURIComponent(segment)).join('/');
const sse = 'AES256';
const canonicalHeaders =
  `content-type:${mimeType}\n` +
  `host:${host}\n` +
  `x-amz-content-sha256:${payloadHash}\n` +
  `x-amz-date:${amzDate}\n` +
  `x-amz-server-side-encryption:${sse}\n`;
const signedHeaders = 'content-type;host;x-amz-content-sha256;x-amz-date;x-amz-server-side-encryption';
const canonicalRequest = [method, canonicalUri, '', canonicalHeaders, signedHeaders, payloadHash].join('\n');
const credentialScope = `${dateStamp}/${region}/${service}/aws4_request`;
const stringToSign = [
  'AWS4-HMAC-SHA256',
  amzDate,
  credentialScope,
  crypto.createHash('sha256').update(canonicalRequest).digest('hex')
].join('\n');

const hmac = (key, data) => crypto.createHmac('sha256', key).update(data).digest();
const kDate = hmac('AWS4' + secretKey, dateStamp);
const kRegion = hmac(kDate, region);
const kService = hmac(kRegion, service);
const kSigning = hmac(kService, 'aws4_request');
const signature = crypto.createHmac('sha256', kSigning).update(stringToSign).digest('hex');
const authorization = `AWS4-HMAC-SHA256 Credential=${accessKey}/${credentialScope}, SignedHeaders=${signedHeaders}, Signature=${signature}`;
const s3Url = `https://${host}${canonicalUri}`;
const binary = await this.helpers.prepareBinaryData(buffer, fileName, mimeType);

console.log('[S3-SIGN] requestId=' + safeRequestId + ' key=' + s3Key + ' bytes=' + buffer.length);

return [{
  json: {
    ...input,
    requestId: safeRequestId,
    userId: typeof safeUserId === 'undefined' ? undefined : safeUserId,
    mimeType,
    fileName,
    s3Bucket: bucket,
    s3Region: region,
    s3Key,
    s3FileKey: s3Key,
    s3FileUrl: s3Url,
    s3Url,
    awsAuthorization: authorization,
    awsXAmzDate: amzDate,
    awsXAmzContentSha256: payloadHash,
    awsXAmzServerSideEncryption: sse
  },
  binary: { data: binary }
}];

const error = $input.first().json;
console.log('[FALLBACK] Primary Gemini 2.5 Flash failed: ' + JSON.stringify(error?.message || error?.error || 'unknown error'));
console.log('[FALLBACK] Routing to fallback model gemini-2.0-flash...');

const contextItem = $('Prepare Context Data').item;
const binaryData = contextItem.binary?.data || null;

return [{
  json: {
    ...contextItem.json,
    _fallbackReason: String(error?.message || error?.error || 'Primary model unavailable')
  },
  binary: binaryData ? { data: binaryData } : undefined
}];

const convertItem = $('Convert + Sign for S3').item;
const originalJson = convertItem.json;
const uploadJson = $('Upload ID Image To S3').item?.json || {};

const uploadStatus = uploadJson.statusCode || uploadJson.status || null;
const uploadEtag = (uploadJson.headers && (uploadJson.headers.etag || uploadJson.headers.ETag)) || null;
const s3UploadSucceeded = uploadStatus ? (uploadStatus >= 200 && uploadStatus < 300) : true;

if (!s3UploadSucceeded) {
  const bodyPreview = typeof uploadJson.body === 'string' ? uploadJson.body.slice(0, 1500) : JSON.stringify(uploadJson.body || uploadJson).slice(0, 1500);
  console.log('[S3-UPLOAD] FAILED status=' + uploadStatus + ' body=' + bodyPreview);
  throw new Error('S3 upload failed (HTTP ' + uploadStatus + '): ' + bodyPreview);
}

const profile = {
  legalFirstName: originalJson.profile?.legalFirstName || '',
  legalMiddleName: originalJson.profile?.legalMiddleName || '',
  legalLastName: originalJson.profile?.legalLastName || '',
  dateOfBirth: originalJson.profile?.dateOfBirth || ''
};

const requestId = originalJson.requestId || '';
const selectedDocumentType = originalJson.selectedDocumentType || '';
const documentSide = originalJson.documentSide || '';
const s3Key = originalJson.s3Key || '';
const s3FileUrl = originalJson.s3FileUrl || originalJson.s3Url || '';
const binaryData = convertItem.binary?.data || null;

console.log('[S3-UPLOAD] OK status=' + uploadStatus + ' etag=' + uploadEtag + ' key=' + s3Key);
console.log('[PREPARE] requestId=' + requestId);
console.log('[PREPARE] s3Key=' + s3Key);
console.log('[PREPARE] profile sent to Gemini: ' + JSON.stringify(profile));
console.log('[PREPARE] docType=' + selectedDocumentType + ' side=' + documentSide);
console.log('[PREPARE] hasBinary=' + (binaryData ? 'YES (' + (binaryData.fileSize || 'unknown size') + ')' : 'NO'));

return [{
  json: {
    requestId,
    selectedDocumentType,
    documentSide,
    profile,
    s3FileKey: s3Key,
    s3FileUrl,
    s3UploadStatus: uploadStatus,
    s3UploadEtag: uploadEtag,
    fileName: originalJson.fileName || '',
    mimeType: originalJson.mimeType || ''
  },
  binary: binaryData ? { data: binaryData } : undefined
}];

const analysisNode = $('Analyze ID Document');
const contextNode = $('Prepare Context Data');
const rawAnalysis = analysisNode?.item?.json || {};
const context = contextNode?.item?.json || {};

console.log('[GEMINI] Raw keys: ' + Object.keys(rawAnalysis).join(','));

function extractJSON(raw) {
  if (raw.documentDetected !== undefined) return raw;
  if (raw.content && raw.content.parts && raw.content.parts[0] && raw.content.parts[0].text) {
    let t = raw.content.parts[0].text.replace(/^```json\s*/, '').replace(/```\s*$/, '').trim();
    try { return JSON.parse(t); } catch(e) { console.log('[PARSE] content.parts failed: ' + e.message); }
  }
  if (raw.text) {
    let t = raw.text.replace(/^```json\s*/, '').replace(/```\s*$/, '').trim();
    try { return JSON.parse(t); } catch(e) { console.log('[PARSE] text failed: ' + e.message); }
  }
  return null;
}

function toFieldMatch(val) {
  if (!val) return { status: 'NOT_CHECKED' };
  if (typeof val === 'string') {
    const s = val.toUpperCase().replace('NAME_','').replace('DOB_','');
    return { status: ['MATCH','MISMATCH','PARTIAL_MATCH','AMBIGUOUS','NOT_CHECKED'].includes(s) ? s : 'NOT_CHECKED' };
  }
  if (typeof val === 'object') {
    const s = String(val.status || 'NOT_CHECKED').toUpperCase().replace('NAME_','').replace('DOB_','');
    return {
      status: ['MATCH','MISMATCH','PARTIAL_MATCH','AMBIGUOUS','NOT_CHECKED'].includes(s) ? s : 'NOT_CHECKED',
      details: val.details || null,
      userProvided: val.userProvided || null,
      documentExtracted: val.documentExtracted || null
    };
  }
  return { status: 'NOT_CHECKED' };
}

function toFlag(f) {
  if (typeof f === 'string') return { severity: 'CRITICAL', code: f, message: f.replace(/_/g, ' ').toLowerCase() };
  return { severity: f.severity || 'CRITICAL', code: f.code || 'UNKNOWN', message: f.message || f.code || 'Unknown issue' };
}

const a = extractJSON(rawAnalysis);

if (!a) {
  console.log('[RESULT] PARSE FAILED');
  const failAnalysis = {
    documentDetected: false, detectedDocumentType: 'unknown', detectedDocumentTypeLabel: 'Unknown',
    documentTypeMatch: false, detectedSide: context.documentSide || 'front', sideMatchesSelected: false,
    userSelectedType: context.selectedDocumentType || 'unknown', userSelectedTypeLabel: 'Unknown',
    extractedFields: {}, validationResults: {
      nameMatch: { status: 'NOT_CHECKED' }, dobMatch: { status: 'NOT_CHECKED' },
      addressMatch: { status: 'NOT_CHECKED' }, expirationStatus: 'UNKNOWN', photoIntegrity: 'CLEAR'
    },
    flags: [{ severity: 'CRITICAL', code: 'ANALYSIS_FAILED', message: 'Could not analyze this document image.' }],
    complianceEligibility: false, nextAction: 'RETAKE_PHOTO', humanReviewRequired: true,
    reviewReason: 'Gemini response could not be parsed'
  };
  return [{ json: { success: false, requestId: context.requestId, source: 'n8n-gemini-vision',
    s3FileKey: context.s3FileKey || null, s3FileUrl: context.s3FileUrl || null,
    userMessage: 'We could not read this document. Please retake the photo with better lighting.',
    analysis: failAnalysis } }];
}

const vr = a.validationResults || {};
const bc = a.booleanChecks || {};
const ef = a.extractedFields || {};

const rawCompliance = typeof a.complianceEligibility === 'boolean' ? a.complianceEligibility
  : typeof a.complianceEligibility === 'object' ? Boolean(a.complianceEligibility?.canContinue)
  : Boolean(bc.canContinue);

let flags = Array.isArray(a.flags) ? a.flags.map(toFlag) : [];

function isFutureIssueDateProblem(value) {
  const text = String(value || '').toUpperCase();
  return text.includes('ISSUE DATE') && (text.includes('FUTURE') || text.includes('NOT YET VALID') || text.includes('NOT-YET-VALID'));
}
function isFutureIssueDateFlag(f) {
  const code = String(f.code || '').toUpperCase();
  const message = String(f.message || '').toUpperCase();
  return ((code.includes('ISSUE') && code.includes('FUTURE')) || code.includes('NOT_YET_VALID') || isFutureIssueDateProblem(message));
}
const removedFutureIssueDateFlag = flags.some(isFutureIssueDateFlag);
flags = flags.filter(f => !isFutureIssueDateFlag(f));
if (removedFutureIssueDateFlag) console.log('[SAFETY] Removed future issue-date flag; issue_date is informational only.');

function isCopyOrScreenshotProblem(value) {
  const text = String(value || '').toUpperCase();
  return text.includes('DOCUMENT_COPY_OR_SCREENSHOT') || text.includes('SCREENSHOT') || text.includes('SCREEN CAPTURE') || text.includes('PHOTO OF A SCREEN') || text.includes('XEROX') || text.includes('PHOTOCOPY') || text.includes('SCANNED COPY') || text.includes('SCAN OF') || text.includes('PRINTED COPY') || text.includes('BLACK-AND-WHITE COPY') || text.includes('BLACK AND WHITE COPY') || text.includes('DIGITAL COPY');
}
function isCopyOrScreenshotFlag(f) {
  return isCopyOrScreenshotProblem(f.code) || isCopyOrScreenshotProblem(f.message);
}
const modelReportedCopyOrScreenshot = flags.some(isCopyOrScreenshotFlag) || isCopyOrScreenshotProblem(a.userMessage);
if (modelReportedCopyOrScreenshot && !flags.some(f => f.code === 'DOCUMENT_COPY_OR_SCREENSHOT')) {
  flags.push({ severity: 'CRITICAL', code: 'DOCUMENT_COPY_OR_SCREENSHOT', message: 'Document appears to be a screenshot, scan, photocopy, or xerox copy instead of the original physical document.' });
  console.log('[SAFETY] Auto-injected CRITICAL DOCUMENT_COPY_OR_SCREENSHOT flag');
}
flags.forEach(f => { if (f.code === 'DOCUMENT_COPY_OR_SCREENSHOT') f.severity = 'CRITICAL'; });

const nmStatus = (typeof vr.nameMatch === 'object' && vr.nameMatch ? (vr.nameMatch.status || '') : (typeof vr.nameMatch === 'string' ? vr.nameMatch : '')).toUpperCase();
const dbStatus = (typeof vr.dobMatch === 'object' && vr.dobMatch ? (vr.dobMatch.status || '') : (typeof vr.dobMatch === 'string' ? vr.dobMatch : '')).toUpperCase();
if (nmStatus === 'MISMATCH' && !flags.some(f => f.code === 'NAME_MISMATCH')) {
  flags.push({ severity: 'CRITICAL', code: 'NAME_MISMATCH', message: 'Name on document does not match profile.' });
  console.log('[SAFETY] Auto-injected CRITICAL NAME_MISMATCH flag');
}
if (dbStatus === 'MISMATCH' && !flags.some(f => f.code === 'DOB_MISMATCH')) {
  flags.push({ severity: 'CRITICAL', code: 'DOB_MISMATCH', message: 'Date of birth on document does not match profile.' });
  console.log('[SAFETY] Auto-injected CRITICAL DOB_MISMATCH flag');
}
flags.forEach(f => { if ((f.code === 'NAME_MISMATCH' || f.code === 'DOB_MISMATCH' || f.code === 'IMAGE_TAMPERING') && f.severity !== 'CRITICAL') { console.log('[SAFETY] Upgrading ' + f.code + ' to CRITICAL'); f.severity = 'CRITICAL'; } });

const hasCriticalFlag = flags.some(f => f.severity === 'CRITICAL');
const hasValidationMismatch = nmStatus === 'MISMATCH' || dbStatus === 'MISMATCH';
const modelMessageMentionsFutureIssueDate = isFutureIssueDateProblem(a.userMessage);
const documentDetectedCheck = Boolean(a.documentDetected);
const documentTypeMatchCheck = a.documentTypeMatch !== undefined ? Boolean(a.documentTypeMatch) : Boolean(bc.documentTypeMatchesSelection);
const sideMatchesCheck = a.sideMatchesSelected !== undefined ? Boolean(a.sideMatchesSelected) : Boolean(bc.sideMatchesSelection !== false);
const modelRejectedOnlyForFutureIssueDate = (removedFutureIssueDateFlag || modelMessageMentionsFutureIssueDate) && documentDetectedCheck && documentTypeMatchCheck && sideMatchesCheck && !hasCriticalFlag && !hasValidationMismatch;
const complianceEligibility = (rawCompliance || modelRejectedOnlyForFutureIssueDate) && !hasCriticalFlag && !hasValidationMismatch;

const labels = { 'drivers-license':'US Driver\'s License','state-id':'US State ID Card','passport':'US Passport',
  'passport-card':'US Passport Card','permanent-resident-card':'US Permanent Resident Card',
  'employment-authorization-card':'US Employment Authorization Card','military-id':'US Military ID','unknown':'Unknown Document' };

let detectedType = a.detectedDocumentType || context.selectedDocumentType || 'unknown';

if (detectedType === 'passport-card') {
  const allFields = JSON.stringify(ef).toUpperCase();
  const hasBookMRZ = allFields.includes('P<USA');
  const labelMentionsBook = (a.detectedDocumentTypeLabel || '').toUpperCase().includes('PASSPORT BOOK');
  const hasMultiplePages = allFields.includes('BOOKLET') || allFields.includes('BOOK');
  if (hasBookMRZ || labelMentionsBook || hasMultiplePages) {
    console.log('[SAFETY] Auto-correcting passport-card -> passport (book cues detected)');
    detectedType = 'passport';
    a.detectedDocumentType = 'passport';
    a.detectedDocumentTypeLabel = 'US Passport';
    if (context.selectedDocumentType === 'passport') a.documentTypeMatch = true;
  }
}
if (detectedType === 'passport') {
  const labelSaysCard = (a.detectedDocumentTypeLabel || '').toUpperCase().includes('PASSPORT CARD');
  if (labelSaysCard) { a.detectedDocumentTypeLabel = 'US Passport'; }
}
const selectedType = a.userSelectedType || context.selectedDocumentType || 'unknown';

const normalizedAnalysis = {
  documentDetected: Boolean(a.documentDetected),
  userSelectedType: selectedType,
  userSelectedTypeLabel: labels[selectedType] || selectedType,
  detectedDocumentType: detectedType,
  detectedDocumentTypeLabel: a.detectedDocumentTypeLabel || labels[detectedType] || detectedType,
  documentTypeMatch: a.documentTypeMatch !== undefined ? Boolean(a.documentTypeMatch) : Boolean(bc.documentTypeMatchesSelection),
  detectedSide: a.detectedSide || context.documentSide || 'front',
  sideMatchesSelected: a.sideMatchesSelected !== undefined ? Boolean(a.sideMatchesSelected) : Boolean(bc.sideMatchesSelection !== false),
  extractedFields: ef,
  validationResults: {
    nameMatch: toFieldMatch(vr.nameMatch),
    dobMatch: toFieldMatch(vr.dobMatch),
    addressMatch: toFieldMatch(vr.addressMatch || 'NOT_CHECKED'),
    expirationStatus: vr.expirationStatus || 'UNKNOWN',
    photoIntegrity: vr.photoIntegrity || 'CLEAR'
  },
  flags,
  complianceEligibility,
  nextAction: modelReportedCopyOrScreenshot ? 'RETAKE_PHOTO' : (a.nextAction || (complianceEligibility ? 'CONTINUE' : 'HALT_VERIFICATION')),
  humanReviewRequired: Boolean(a.humanReviewRequired ?? !complianceEligibility),
  reviewReason: a.reviewReason || null
};

console.log('\n========== VERIFICATION LOG ==========');
console.log('[ID] request=' + context.requestId + ' s3Key=' + (context.s3FileKey || 'none'));
console.log('[DOC] detected=' + normalizedAnalysis.documentDetected + ' type=' + normalizedAnalysis.detectedDocumentType + ' match=' + normalizedAnalysis.documentTypeMatch);
console.log('[DOC] side=' + normalizedAnalysis.detectedSide + ' sideMatch=' + normalizedAnalysis.sideMatchesSelected);
console.log('[EXTRACT] name=' + (ef.first_name||'?') + ' ' + (ef.last_name||'?') + ' DOB=' + (ef.date_of_birth||'?') + ' EXP=' + (ef.expiration_date||'?'));
console.log('[PROFILE] ' + context.profile?.legalFirstName + ' ' + context.profile?.legalLastName + ' DOB=' + context.profile?.dateOfBirth);
console.log('[CHECK] name=' + normalizedAnalysis.validationResults.nameMatch.status + ' dob=' + normalizedAnalysis.validationResults.dobMatch.status + ' exp=' + normalizedAnalysis.validationResults.expirationStatus);
console.log('[DECISION] compliance=' + complianceEligibility + ' action=' + normalizedAnalysis.nextAction + ' review=' + normalizedAnalysis.humanReviewRequired);
console.log('[FLAGS] ' + JSON.stringify(normalizedAnalysis.flags));
const finalUserMessage = modelReportedCopyOrScreenshot
  ? 'Please upload a clear photo of the original physical document. Screenshots, scans, photocopies, and xerox copies cannot be accepted.'
  : (modelMessageMentionsFutureIssueDate
    ? (complianceEligibility ? 'Your document has been verified successfully.' : 'There was an issue verifying your document. Please check the details below.')
    : (a.userMessage || (complianceEligibility ? 'Your document has been verified successfully.' : 'There was an issue verifying your document. Please check the details below.')));
console.log('[MSG] ' + (finalUserMessage || 'none'));
console.log('=======================================\n');

return [{ json: {
  success: true,
  requestId: context.requestId,
  source: 'n8n-gemini-vision',
  s3FileKey: context.s3FileKey || null,
  s3FileUrl: context.s3FileUrl || null,
  userMessage: finalUserMessage,
  analysis: normalizedAnalysis
} }];
